using System.Diagnostics;
using System.Runtime.InteropServices.ComTypes;

namespace Microsoft.CSharp.RuntimeBinder.ComInterop
{
    internal sealed class ComMethodDesc
    {
        private readonly INVOKEKIND _invokeKind;

        private ComMethodDesc(int dispId)
        {
            DispId = dispId;
        }

        internal ComMethodDesc(string name, int dispId)
            : this(dispId)
        {
            // no ITypeInfo constructor
            Name = name;
        }

        internal ComMethodDesc(string name, int dispId, INVOKEKIND invkind)
            : this(name, dispId)
        {
            _invokeKind = invkind;
        }

        internal ComMethodDesc(ITypeInfo typeInfo, FUNCDESC funcDesc)
            : this(funcDesc.memid)
        {
            _invokeKind = funcDesc.invkind;

            string[] rgNames = new string[1 + funcDesc.cParams];
            typeInfo.GetNames(DispId, rgNames, rgNames.Length, out int cNames);
            if (IsPropertyPut && rgNames[rgNames.Length - 1] == null)
            {
                rgNames[rgNames.Length - 1] = "value";
                cNames++;
            }
            Debug.Assert(cNames == rgNames.Length);
            Name = rgNames[0];

            ParamCount = funcDesc.cParams;
        }

        public string Name { get; }

        public int DispId { get; }

        public bool IsPropertyGet
        {
            get
            {
                return (_invokeKind & INVOKEKIND.INVOKE_PROPERTYGET) != 0;
            }
        }

        public bool IsDataMember
        {
            get
            {
                //must be regular get
                if (!IsPropertyGet || DispId == ComDispIds.DISPID_NEWENUM)
                {
                    return false;
                }

                //must have no parameters
                return ParamCount == 0;
            }
        }

        public bool IsPropertyPut
        {
            get
            {
                return (_invokeKind & (INVOKEKIND.INVOKE_PROPERTYPUT | INVOKEKIND.INVOKE_PROPERTYPUTREF)) != 0;
            }
        }

        public bool IsPropertyPutRef
        {
            get
            {
                return (_invokeKind & INVOKEKIND.INVOKE_PROPERTYPUTREF) != 0;
            }
        }

        internal int ParamCount { get; }
    }
}

namespace ScottPlot;

public static class DataOperations
{
    public static double[,] ResizeHalf(double[,] values)
    {
        int height = values.GetLength(0);
        int width = values.GetLength(1);

        int heightNew = (int)Math.Floor((double)height / 2);
        int widthNew = (int)Math.Floor((double)width / 2);

        double[,] output = new double[heightNew, widthNew];

        for (int y = 0; y < heightNew; y++)
        {
            for (int x = 0; x < widthNew; x++)
            {
                double sum = 0;
                sum += values[y * 2, x * 2];
                sum += values[y * 2 + 1, x * 2];
                sum += values[y * 2, x * 2 + 1];
                sum += values[y * 2 + 1, x * 2 + 1];
                output[y, x] = sum / 4;
            }
        }

        return output;
    }

    public static double[,] ReplaceNullWithNaN(double?[,] values)
    {
        int height = values.GetLength(0);
        int width = values.GetLength(1);
        double[,] output = new double[height, width];

        for (int y = 0; y < height; y++)
        {
            for (int x = 0; x < width; x++)
            {
                output[y, x] = values[y, x] ?? double.NaN;
            }
        }

        return output;
    }

    public static double?[,] ReplaceNaNWithNull(double[,] values)
    {
        int height = values.GetLength(0);
        int width = values.GetLength(1);
        double?[,] output = new double?[height, width];

        for (int y = 0; y < height; y++)
        {
            for (int x = 0; x < width; x++)
            {
                output[y, x] = double.IsNaN(values[y, x]) ? null : values[y, x];
            }
        }

        return output;
    }

    public static void Multiply2D(double[,] values, double mult)
    {
        for (int i = 0; i < values.GetLength(0); i++)
        {
            for (int j = 0; j < values.GetLength(1); j++)
            {
                values[i, j] *= mult;
            }
        }
    }

    public static double[] SumVertically(IEnumerable<double[]> arrays)
    {
        double[] result = new double[arrays.First().Length];
        foreach (double[] array in arrays)
        {
            if (array.Length != result.Length)
                throw new InvalidDataException("All arrays must have equal length");

            for (int i = 0; i < result.Length; i++)
            {
                result[i] += array[i];
            }
        }

        return result;
    }
}

